'use client'

import { useState, useEffect } from 'react'

export default function BookSessionModal() {
  const [open, setOpen] = useState(false)

  // Auto open after delay
  useEffect(() => {
    const timer = setTimeout(() => {
      setOpen(true)
    }, 3000) // popup after 3 seconds

    return () => clearTimeout(timer)
  }, [])

  if (!open) return null

  return (
    <div
      className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-6"
      onClick={() => setOpen(false)}
    >
      <div
        className="bg-[#1a1a1a] border border-gold rounded-xl w-full max-w-lg p-8 relative animate-fadeIn"
        onClick={(e) => e.stopPropagation()}
      >
        <h2 className="text-3xl font-display text-gold mb-6 text-center">
          Book a Session
        </h2>

        <form className="space-y-4">
          <input
            type="text"
            placeholder="Full Name"
            className="w-full bg-black border border-white/20 px-4 py-3 rounded text-white"
          />

          <input
            type="email"
            placeholder="Email Address"
            className="w-full bg-black border border-white/20 px-4 py-3 rounded text-white"
          />

          <input
            type="tel"
            placeholder="Phone Number"
            className="w-full bg-black border border-white/20 px-4 py-3 rounded text-white"
          />

          <select className="w-full bg-black border border-white/20 px-4 py-3 rounded text-white">
            <option>Select Session Type</option>
            <option>Wedding</option>
            <option>Pre-Wedding</option>
            <option>Fashion</option>
            <option>Album Design</option>
          </select>

          <button
            type="submit"
            className="w-full bg-gold text-black py-3 rounded font-bold hover:bg-yellow-400 transition"
          >
            Submit
          </button>
        </form>

        <button
          onClick={() => setOpen(false)}
          className="absolute top-4 right-4 text-gold text-xl"
        >
          ✕
        </button>
      </div>
    </div>
  )
}
